import { CommonModule } from '@angular/common';
import { Component, inject, computed, OnInit } from '@angular/core';
import { AbstractControl, FormControl, FormGroup, ReactiveFormsModule, ValidationErrors, ValidatorFn, Validators } from '@angular/forms';
import { MatCardModule } from '@angular/material/card';
import { MatIconModule } from '@angular/material/icon';
import { MatFormField, MatInputModule, MatLabel } from '@angular/material/input';
import { AuthService } from '../auth.service';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { SnackbarService } from '../../shared/snack-bar/snack-bar.service';
import { LoginSignalService } from '../login/login.signal.service';
import { MatButtonModule } from '@angular/material/button';
import { LoaderService } from '../../shared/loader/loader.service';
import { LoaderComponent } from '../../shared/loader/loader.component';

@Component({
  selector: 'app-forget-pswd',
  standalone: true,
  imports: [ReactiveFormsModule, CommonModule, MatIconModule, MatInputModule, MatCardModule, MatLabel, MatFormField, RouterModule, MatButtonModule, LoaderComponent],
  templateUrl: './forget-pswd.component.html',
  styleUrl: './forget-pswd.component.css'
})
export class ForgetPswdComponent implements OnInit {
  private loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());
  currentStep: number = 1;
  username: string = '';
  uuid: string = '';
  hide = true;
  hideConfirm = true;
  passwordreset_token: string = '';
  hasEmail: boolean = true;
  statusMessage: string = '';
  disbursementToken: string | null = null;
  isDisbursementMode = false;

  forgotForm = new FormGroup({
    username: new FormControl('', [Validators.required])
  });

  otpForm = new FormGroup({
    otp: new FormControl('', [Validators.required, Validators.minLength(6), Validators.maxLength(6)])
  });

  passwordForm = new FormGroup({
    newPassword: new FormControl('', [Validators.required, Validators.minLength(8)]),
    confirmPassword: new FormControl('', [Validators.required])
  }, { validators: this.passwordMatchValidator() });

  constructor(private authservice: AuthService, private router: Router, private snackBar: SnackbarService,
    private loginSignal: LoginSignalService, private route: ActivatedRoute
  ) {

  }

  ngOnInit() {

  }

  passwordMatchValidator(): ValidatorFn {
    return (control: AbstractControl): ValidationErrors | null => {
      const newPassword = control.get('newPassword');
      const confirmPassword = control.get('confirmPassword');

      if (!newPassword || !confirmPassword) {
        return null;
      }

      return newPassword.value === confirmPassword.value ? null : { passwordMismatch: true };
    };
  }

  onSubmitUsername() {
    if (this.forgotForm.valid) {
      const { username } = this.forgotForm.value;
      this.username = username!;

      this.loader.show();
      this.authservice.forgotpassword(username!).subscribe({
        next: (res) => {
          this.loader.hide();
          if (res.screen == 'Check Your Email') {
            this.snackBar.showSuccess(res.message);
            this.router.navigate(['login']);
          } else {
            this.snackBar.showError(res.message);
            this.router.navigate(['login']);

          }
        },
        error: (err) => {
          this.loader.hide();
          const errmsg = err.error?.error || 'Something went wrong. Please try again.';
          this.snackBar.showError(errmsg);
        }
      });
    }
  }

  backToLogin() {
    this.router.navigate(['login']);
  }

}
